external_knowledge:
- "celestial explorers" refers to successful space missions;
- "grand vessels" are rockets used for the launches;
- "voyages' destinations" are the missions these rockets undertake;
- "captains who commanded them" are the launch service providers;
- "ports from which they sailed" are the launch sites;
- "charted course documents" refer to the mission briefs;
- "since the dawn of the new millennium" means after January 1, 2000.

sql:
SELECT name, destination 
FROM missions
ORDER BY name DESC;

external_knowledge:
- "companies" refers to launch service providers in the context of space launches; 
- "missions" refer to specific space-related objectives or tasks carried out by the launches;
- "total weight of the payloads" is the cumulative mass of payloads for all launches related to a particular combination of a launch service provider and a mission.

sql:
SELECT name, description
FROM rockets
WHERE payload_capacity > 10000 AND payload_capacity <= 20000;

SELECT COUNT(*)
FROM mission_outcomes
WHERE outcome_type = 'mission success';

SELECT name 
FROM missions 
WHERE type = 'uncrewed';

SELECT l.name, p.payload_mass
FROM launches l
JOIN payloads p ON l.launch_id = p.launch_id
WHERE p.payload_mass = (
    SELECT MAX(payload_mass) FROM payloads
);

SELECT name, country, website
FROM launch_service_providers
WHERE launch_service_provider_id = 1;

SELECT crew_name, crew_experience
FROM crew
WHERE crew_name = 'John Smith';

SELECT name, country
FROM launch_service_providers
WHERE name LIKE '%SpaceX%';

external_knowledge:
- "successful voyages from the US" refers to the launches with status 'Success' and providers from the 'United States';
- "vessels sails with a mighty load of a thousand or more" means rockets with a payload capacity of 1000 units or more;
- "crew that guides them numbers more than a handful" signifies more than 5 crew members;
- "average weight of the celestial cargo" refers to the average payload mass;
- "average size of the crew" is the average crew size.

sql:
SELECT m.name
FROM missions m
INNER JOIN launch_sites ls ON m.destination = ls.location;
